### Deobfuscated Code

```javascript
// Configuration for the pathfinding algorithm
const config = {
    penalty: 'manhattan',
    adjacentCost: 1.414, // Diagonal movement cost (approx. sqrt(2))
    traversalCost: 1,    // Orthogonal movement cost (up/down/left/right)
    minIterations: 1000, // Maximum allowed iterations before giving up
    clearanceRatio: 0.25 // 25% chance for a cell to be an obstacle
};

const gridWidth = 20;
const gridHeight = 15;
const grid = [];

// Generate a 20x15 grid with random obstacles
for (let y = 0; y < gridHeight; y++) {
    grid[y] = [];
    for (let x = 0; x < gridWidth; x++) {
        // 1 represents an obstacle, 0 represents a walkable path
        grid[y][x] = Math.random() < config.clearanceRatio ? 1 : 0;
    }
}

// Define the start and end points
const originNode = { x: 0, y: 0 };
const waypointNode = { x: gridWidth - 1, y: gridHeight - 1 };

// Ensure the start and end points are never blocked
grid[originNode.y][originNode.x] = 0;
grid[waypointNode.y][waypointNode.x] = 0;

// Helper function to create a unique string key for a coordinate
function nodeKey(node) {
    return node.x + ',' + node.y;
}

// Helper function to calculate the heuristic (distance) between two nodes
function measureProximity(nodeA, nodeB) {
    let dx = Math.abs(nodeA.x - nodeB.x);
    let dy = Math.abs(nodeA.y - nodeB.y);

    if (config.penalty === 'manhattan') {
        return dx + dy; // Manhattan distance
    }
    return Math.sqrt(dx * dx + dy * dy); // Euclidean distance
}

// Helper function to get valid surrounding nodes (8-way movement)
function getAncestors(node) {
    let validNeighbors = [];
    let moves = [
        { dx: 0, dy: -1, cost: config.traversalCost }, // Up
        { dx: 0, dy: 1, cost: config.traversalCost },  // Down
        { dx: -1, dy: 0, cost: config.traversalCost }, // Left
        { dx: 1, dy: 0, cost: config.traversalCost },  // Right
        { dx: -1, dy: -1, cost: config.adjacentCost }, // Top-Left
        { dx: 1, dy: -1, cost: config.adjacentCost },  // Top-Right
        { dx: -1, dy: 1, cost: config.adjacentCost },  // Bottom-Left
        { dx: 1, dy: 1, cost: config.adjacentCost }    // Bottom-Right
    ];

    for (let i = 0; i < moves.length; i++) {
        let targetX = node.x + moves[i].dx;
        let targetY = node.y + moves[i].dy;

        // Ensure the move is within grid bounds and is not an obstacle (0)
        if (targetX >= 0 && targetX < gridWidth && 
            targetY >= 0 && targetY < gridHeight && 
            grid[targetY][targetX] === 0) {

            validNeighbors.push({ 
                x: targetX, 
                y: targetY, 
                moveCost: moves[i].cost 
            });
        }
    }
    return validNeighbors;
}

// Core A* Pathfinding algorithm
function findRoute(startNode, targetNode) {
    let startKey = nodeKey(startNode);

    let openSet = {};
    openSet[startKey] = startNode;

    let gScore = {}; // Cost from start along best known path
    gScore[startKey] = 0;

    let fScore = {}; // Estimated total cost from start to goal
    fScore[startKey] = measureProximity(startNode, targetNode);

    let closedSet = {};
    let cameFrom = {}; // Used to reconstruct the final path
    let iterations = 0;

    // Loop while there are nodes to evaluate and we haven't hit the iteration limit
    while (Object.keys(openSet).length > 0 && iterations < config.minIterations) {
        iterations++;

        let currentKey = null;
        let lowestFScore = Infinity;

        // Find the node in openSet with the lowest fScore
        for (let key in openSet) {
            if (fScore[key] < lowestFScore) {
                lowestFScore = fScore[key];
                currentKey = key;
            }
        }

        let currentNode = openSet[currentKey];

        // Check if we have reached the target
        if (currentNode.x === targetNode.x && currentNode.y === targetNode.y) {
            let path = [currentNode];
            let traceKey = currentKey;

            // Reconstruct the path backwards
            while (cameFrom[traceKey]) {
                traceKey = cameFrom[traceKey];
                let nodeData = openSet[traceKey] || closedSet[traceKey] || { 
                    x: parseInt(traceKey.split(',')[0]), 
                    y: parseInt(traceKey.split(',')[1]) 
                };
                path.unshift(nodeData); 
            }
            return { path: path, cost: gScore[currentKey], iterations: iterations };
        }

        // Move current node from openSet to closedSet
        delete openSet[currentKey];
        closedSet[currentKey] = currentNode;

        // Evaluate all valid neighbors
        let neighbors = getAncestors(currentNode);
        for (let i = 0; i < neighbors.length; i++) {
            let neighbor = neighbors[i];
            let neighborKey = nodeKey(neighbor);

            // Skip if already evaluated
            if (closedSet[neighborKey]) continue;

            let tentativeGScore = gScore[currentKey] + neighbor.moveCost;

            // If it's a new node or we found a shorter path to it
            if (gScore[neighborKey] === undefined || tentativeGScore < gScore[neighborKey]) {
                cameFrom[neighborKey] = currentKey;
                gScore[neighborKey] = tentativeGScore;
                fScore[neighborKey] = tentativeGScore + measureProximity(neighbor, targetNode);
                openSet[neighborKey] = neighbor;
            }
        }
    }

    // Failed to find a path
    return { path: [], cost: Infinity, iterations: iterations };
}

// Execute the pathfinding and log the results
const result = findRoute(originNode, waypointNode);
console.log("Path Found:", result.path.length, "Cost:", result.cost, "Iterations:", result.iterations);
```

### Explanation of What It Does

This script implements an **A* (A-Star) Pathfinding Algorithm** on a 2D grid. Here's a breakdown of its components:

1.  **Grid Generation**:
    It creates a `20x15` coordinate grid. It populates this grid randomly with "obstacles" (represented by `1`) and "walkable paths" (represented by `0`). Based on `config.clearanceRatio`, roughly 25% of the map will be blocked. It ensures the start `(0,0)` and end `(19, 14)` are forced to be walkable.
2.  **Heuristics (`measureProximity`)**:
    A* relies on estimating the remaining distance to the goal to prioritize which direction to search. This script configures a `manhattan` distance (calculating distance purely using grid squares, no diagonals). If changed, it falls back to a standard Euclidean (straight-line) calculation.
3.  **Neighbor Checking (`getAncestors`)**:
    This checks all 8 adjacent tiles around a coordinate. Orthogonal movement (Up, Down, Left, Right) costs `1`, while diagonal movement costs `1.414` (the mathematical square root of 2). It ignores tiles that fall outside the map boundaries or contain obstacles.
4.  **The Main Loop (`findRoute`)**:
    *   It maintains an `openSet` (nodes to check) and a `closedSet` (nodes already checked).
    *   It checks the node with the lowest `fScore` (Distance from start + Estimated distance to target).
    *   Once the target is found, it uses the `cameFrom` object to trace its steps backward to the origin point, returning the final array of coordinates (the shortest path).
    *   *(Note: The original author named the setting `minIterations`, but it is actually functioning as a `maxIterations` circuit breaker to prevent the loop from running forever if a path is entirely blocked).*
5.  **Output**:
    Finally, it prints the amount of steps the path took, the total movement cost, and how many nodes it had to evaluate (iterations) to find the route.
